import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getMovies } from '../services/api';

const Home = () => {
  const [movies, setMovies] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadMovies();
  }, []);

  const loadMovies = async () => {
    try {
      const data = await getMovies();
      setMovies(data);
    } catch (error) {
      console.error('Error cargando películas:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) return <div className="p-8">Cargando...</div>;

  return (
    <div className="p-8">
      <div className="flex justify-between items-center mb-8">
        <h1 className="text-4xl font-bold">RaulFlix</h1>
        <Link 
          to="/admin" 
          className="bg-gray-700 hover:bg-gray-600 px-4 py-2 rounded"
        >
          Admin
        </Link>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
        {movies.map(movie => (
          <Link key={movie.id} to={`/movie/${movie.id}`} className="group">
            <div className="bg-gray-800 rounded-lg overflow-hidden hover:scale-105 transition-transform">
              <img 
                src={movie.poster || 'https://via.placeholder.com/300x450/374151/9CA3AF?text=Sin+Imagen'} 
                alt={movie.title}
                className="w-full h-64 object-cover"
                onError={(e) => {
                  e.target.src = 'https://via.placeholder.com/300x450/374151/9CA3AF?text=Sin+Imagen';
                }}
              />
              <div className="p-3">
                <h3 className="font-semibold truncate">{movie.title}</h3>
                <p className="text-sm text-gray-400">{movie.year}</p>
              </div>
            </div>
          </Link>
        ))}
      </div>
    </div>
  );
};

export default Home;
